+      const mean = Array(dim).fill(0);
+      cands.forEach((v) => v.forEach((val, i) => { mean[i] += val; }));
+      mean.forEach((_, i) => { mean[i] /= cands.length; });
+      const cov = Array.from({ length: dim }, () => Array(dim).fill(0));
+      cands.forEach((v) => {
+        for (let i = 0; i < dim; i++) {
+          const a = v[i] - mean[i];
+          for (let j = 0; j < dim; j++) cov[i][j] += a * (v[j] - mean[j]);
