+      const powerVec = (M) => {
+        let v = Array.from({ length: dim }, () => Math.random());
+        const norm = (arr) => Math.sqrt(arr.reduce((s, x) => s + x * x, 0));
+        for (let it = 0; it < 25; it++) {
